import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Page } from '../components/Layout';
import { registerCustomer } from '../services/authService';

const initialForm = {
  firstname: '',
  lastname: '',
  email: '',
  password: '',
  contact: '',
  address: '',
  licenseNumber: '',
  licenseExpiry: ''
};

export default function RegisterPage() {
  const navigate = useNavigate();
  const [form, setForm] = useState(initialForm);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (event) => {
    setForm({ ...form, [event.target.name]: event.target.value });
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    try {
      const data = await registerCustomer(form);
      if (!data.success) {
        setError(data.message || 'Registration failed');
        setLoading(false);
        return;
      }

      setSuccess('Registered successfully. Please login.');
      setTimeout(() => navigate('/login'), 900);
    } catch (err) {
      setError(err?.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Page title="Create Customer Account" subtitle="Register with your details and driving license information.">
      <form className="card formCard grid twoCol" onSubmit={handleSubmit}>
        {error && <div className="alert error full">{error}</div>}
        {success && <div className="alert success full">{success}</div>}
        <label>
          First name
          <input name="firstname" value={form.firstname} onChange={handleChange} />
        </label>
        <label>
          Last name
          <input name="lastname" value={form.lastname} onChange={handleChange} />
        </label>
        <label className="full">
          Email
          <input name="email" value={form.email} onChange={handleChange} type="email" />
        </label>
        <label className="full">
          Password
          <input name="password" value={form.password} onChange={handleChange} type="password" />
        </label>
        <label>
          Contact
          <input name="contact" value={form.contact} onChange={handleChange} />
        </label>
        <label>
          License expiry
          <input name="licenseExpiry" value={form.licenseExpiry} onChange={handleChange} type="date" />
        </label>
        <label className="full">
          License number
          <input name="licenseNumber" value={form.licenseNumber} onChange={handleChange} />
        </label>
        <label className="full">
          Address
          <textarea name="address" value={form.address} onChange={handleChange} rows="4" />
        </label>
        <button className="button full" disabled={loading} type="submit">
          {loading ? 'Registering...' : 'Register'}
        </button>
      </form>
    </Page>
  );
}
